// Normalizza i dati dal form Tally → campi comuni
const items = $input.all();
return items.map(item => {
  const j = item.json;
  const nome_raw = j.question_48G8rb?.value || '';
  const nome_cliente = nome_raw.trim().toUpperCase().replace(/\s+/g, ' ');
  const dn_raw = j.question_jyEyPR?.value || '';
  const data_nascita = dn_raw ? dn_raw.split('-').reverse().join('/') : '________________';
  const email_raw = j.question_N6O6oG?.value || '';
  const email = email_raw.trim().toLowerCase();
  const cf_raw = j.question_9WrWDG?.value || '';
  const codice_fiscale = cf_raw.trim().toUpperCase();
  const df_raw = j.question_a6l6Y9?.value || '';
  const data_firma = df_raw ? df_raw.split('-').reverse().join('/') : new Date().toLocaleDateString('it-IT');
  return {
    json: {
      nome_cliente,
      data_nascita,
      citta: j.question_2eRePp?.value || '________________',
      residenza: j.question_xp6pYG?.value || '________________',
      telefono: j.question_ZNQNa0?.value || '________________',
      email,
      tipo_documento: j.question_qdNdV2?.value || '________________',
      numero_documento: j.question_QDEDVg?.value || '________________',
      codice_fiscale,
      parte_corpo: j.question_WNZN5J?.value || '________________',
      data_firma,
      firma_url: j.question_67V72e?.value || '',
      autorizza_immagini: 'Si',
      lang: 'it',
      source: 'tally'
    }
  };
});

// Recupera i dati normalizzati da Tally
// Usa l'URL della firma direttamente come src dell'img — PDFShift la scarica da solo
const normalizedData = $('Normalize Tally').item.json;
const firma_base64 = normalizedData.firma_url || '';
return [{ json: { ...normalizedData, firma_base64 } }];

// Normalizza i dati dal webhook della pagina HTML → campi comuni
const items = $input.all();
return items.map(item => {
  let body = item.json.body || item.json;
  // text/plain → body arriva come stringa, serve JSON.parse
  if (typeof body === 'string') { try { body = JSON.parse(body); } catch(e) {} }
  const nome_raw = body.nome_cognome || '';
  const nome_cliente = nome_raw.trim().toUpperCase().replace(/\s+/g, ' ');
  const dn_raw = body.data_nascita || '';
  let data_nascita = dn_raw;
  if (/^\d{4}-\d{2}-\d{2}$/.test(dn_raw)) {
    data_nascita = dn_raw.split('-').reverse().join('/');
  }
  const cf_raw = body.codice_fiscale || '';
  const codice_fiscale = cf_raw.trim().toUpperCase();
  const email_raw = body.email || '';
  const email = email_raw.trim().toLowerCase();
  const lang = body.lang || (body.source === 'website_consenso_en' ? 'en' : 'it');
  const df_raw = body.data_firma || '';
  let data_firma = df_raw;
  if (/^\d{4}-\d{2}-\d{2}$/.test(df_raw)) {
    data_firma = df_raw.split('-').reverse().join('/');
  }
  return {
    json: {
      nome_cliente,
      data_nascita: data_nascita || '________________',
      citta: body.citta_nascita || '________________',
      residenza: body.indirizzo || '________________',
      telefono: body.telefono || '________________',
      email,
      tipo_documento: body.tipo_documento || '________________',
      numero_documento: body.numero_documento || '________________',
      codice_fiscale,
      parte_corpo: body.parte_corpo || '________________',
      data_firma: data_firma || new Date().toLocaleDateString(lang === 'en' ? 'en-GB' : 'it-IT'),
      firma_base64: body.firma_base64 || '',
      autorizza_immagini: body.autorizza_immagini || 'No',
      lang,
      source: body.source || 'website'
    }
  };
});

// Costruisce l'HTML del consenso in IT o EN
const item = $input.first().json;
const lang = item.lang || 'it';
const isEN = lang === 'en';
const f = v => v || '________________';
const nome = f(item.nome_cliente);
const dn = f(item.data_nascita);
const citta = f(item.citta);
const res = f(item.residenza);
const tel = f(item.telefono);
const mail = f(item.email);
const tipoDoc = f(item.tipo_documento);
const numDoc = f(item.numero_documento);
const cf = f(item.codice_fiscale);
const corpo = f(item.parte_corpo);
const firma_data = f(item.data_firma);
const showAutorizzo = item.autorizza_immagini === 'Si' || item.autorizza_immagini === 'Yes';

const css = `*{margin:0;padding:0;box-sizing:border-box}@page{size:A4;margin:12mm 10mm}body{font-family:'Times New Roman',Times,serif;max-width:800px;margin:0 auto;line-height:1.6;color:#000;font-size:10.5pt;background:white}.header{text-align:center;margin-bottom:20px;padding-bottom:10px;border-bottom:2px solid #000}.title{font-size:16pt;font-weight:bold;text-transform:uppercase;letter-spacing:2px}.content{text-align:justify;margin-bottom:10px}.section-title{text-align:center;font-weight:bold;margin:14px 0 7px;text-transform:uppercase;font-size:10.5pt;letter-spacing:1px}.bullet-list{margin-left:18px;margin-bottom:10px}.bullet-list li{margin-bottom:3px}.data-field{font-weight:bold}.divider{border-top:1px solid #000;margin:20px 0 15px}.footer{margin-top:20px;display:grid;grid-template-columns:1fr 1fr;gap:20px;align-items:start}.label-text{font-weight:bold;font-size:10.5pt;margin-bottom:8px}.consenso{text-align:center;font-weight:bold;text-transform:uppercase;font-size:10.5pt;margin:18px 0;padding:8px;border:2px solid #000}.nota{font-size:9pt;margin-top:15px;padding:8px;line-height:1.4;font-style:italic}`;

const firmaLine = `<div style='display:inline-block;width:200px;border-top:1px solid #000;margin-top:30px'></div>`;
const firmaImg = item.firma_base64 || '';
const firmaTag = firmaImg ? `<img src='${firmaImg}' style='max-width:200px;max-height:80px;display:inline-block;margin-top:8px'>` : firmaLine;

const autorizzoIT = `<div class='section-title'>AUTORIZZO INOLTRE IRENE GIPSY TATTOO</div><div class='content'><p>a titolo gratuito, senza limiti di tempo, anche ai sensi degli artt. 10 e 320 cod. civ. e degli artt. 96 e 97 legge 22.4.1941, n.633, Legge sul diritto d&apos;autore, alla pubblicazione e/o diffusione in qualsiasi delle mie immagini sul sito Internet di Irene Gipsy Tattoo, su carta stampata e/o qualsiasi altro mezzo di diffusione, nonch&eacute; autorizzo la conservazione delle foto e dei video stessi negli archivi informatici della Societ&agrave;/Ente e prendo atto che la finalit&agrave; di tali pubblicazioni sono meramente di carattere informativo ed eventualmente promozionale.</p></div>`;

const autorizzoEN = `<div class='section-title'>I FURTHERMORE AUTHORISE IRENE GIPSY TATTOO</div><div class='content'><p>free of charge, without time limits, also pursuant to arts. 10 and 320 of the Civil Code and arts. 96 and 97 of Law 22.4.1941, n.633 (Copyright Law), to publish and/or distribute any of my images on the Irene Gipsy Tattoo website, in print and/or any other medium, and I also authorise the storage of said photos and videos in the Company&apos;s digital archives, acknowledging that the purpose of such publications is purely informational and potentially promotional.</p></div>`;

let html;
if (isEN) {
  html = `<!DOCTYPE html><html lang='en'><head><meta charset='UTF-8'><title>Consent Form</title><style>${css}</style></head><body><div class='header'><div class='title'>CONSENT FORM</div></div><div class='content'><p>I the undersigned <span class='data-field'>${nome}</span>, born on <span class='data-field'>${dn}</span> in <span class='data-field'>${citta}</span>, residing at <span class='data-field'>${res}</span>, phone <span class='data-field'>${tel}</span>, e-mail <span class='data-field'>${mail}</span>, ID type <span class='data-field'>${tipoDoc}</span> n. <span class='data-field'>${numDoc}</span>, tax code <span class='data-field'>${cf}</span></p></div><div class='section-title'>I REQUEST:</div><div class='content'><p>The execution of a tattoo on: <span class='data-field'>${corpo}</span></p></div><div class='section-title'>I HAVE BEEN INFORMED OF:</div><ul class='bullet-list'><li>Treatment methods</li><li>Potential health risks</li><li>Correct aftercare of the tattooed area</li><li>Difficulties of removal</li></ul><div class='section-title'>I FURTHER DECLARE:</div><ul class='bullet-list'><li>I have disclosed any conditions that may contraindicate the procedure.</li><li>I have fully understood all information provided.</li><li>I acknowledge that <strong>it is not permitted to bring accompaniers during the tattoo session</strong>.</li></ul>${autorizzoEN}<div class='consenso'>THEREFORE I CONSENT TO THE EXECUTION OF THE TATTOO</div><div class='nota'>Any touch-ups may be carried out free of charge within one month of the session. After this period, a touch-up will be possible upon payment of a fee to be agreed with the artist following a prior consultation.</div><div class='divider'></div><div class='footer'><div><div class='label-text'>DATE: ${firma_data}</div></div><div style='text-align:right'><div class='label-text'>SIGNATURE<br><span style='font-size:9pt;font-weight:normal'>(Parent/guardian if minor)</span></div>${firmaTag}</div></div></body></html>`;
} else {
  html = `<!DOCTYPE html><html lang='it'><head><meta charset='UTF-8'><title>Modulo di Consenso</title><style>${css}</style></head><body><div class='header'><div class='title'>MODULO DI CONSENSO</div></div><div class='content'><p>Io sottoscritto/a <span class='data-field'>${nome}</span>, nato/a il <span class='data-field'>${dn}</span> a <span class='data-field'>${citta}</span>, residente in <span class='data-field'>${res}</span>, telefono <span class='data-field'>${tel}</span>, e-mail <span class='data-field'>${mail}</span>, tipo documento <span class='data-field'>${tipoDoc}</span> n. <span class='data-field'>${numDoc}</span>, codice fiscale <span class='data-field'>${cf}</span></p></div><div class='section-title'>RICHIEDO:</div><div class='content'><p>La realizzazione di un tatuaggio nella seguente parte del corpo: <span class='data-field'>${corpo}</span></p></div><div class='section-title'>DICHIARO DI ESSERE STATO INFORMATO SU:</div><ul class='bullet-list'><li>Modalit&agrave; del trattamento</li><li>Rischi potenziali per la salute</li><li>Corretto trattamento della zona tatuata</li><li>Difficolt&agrave; di rimozione</li></ul><div class='section-title'>DICHIARO INOLTRE:</div><ul class='bullet-list'><li>Di aver riferito eventuali condizioni che possono controindicare il trattamento.</li><li>Di aver ben compreso tutte le informazioni fornite.</li><li>Di essere a conoscenza che <strong>non &egrave; consentito portare accompagnatori durante la seduta di tatuaggio</strong>.</li></ul>${autorizzoIT}<div class='consenso'>PERTANTO ACCONSENTO ALL'ESECUZIONE DEL TATUAGGIO</div><div class='nota'>Eventuali ritocchi potranno essere effettuati gratuitamente entro un mese dalla seduta. Decorso tale periodo, il ritocco sar&agrave; possibile previo pagamento di un corrispettivo economico da concordare con il tatuatore a seguito di preventiva consulenza.</div><div class='divider'></div><div class='footer'><div><div class='label-text'>DATA: ${firma_data}</div></div><div style='text-align:right'><div class='label-text'>FIRMA<br><span style='font-size:9pt;font-weight:normal'>(Di genitore in caso di minore)</span></div>${firmaTag}</div></div></body></html>`;
}

return [{ json: { ...item, html } }];

// Pre-genera il nome file PDF pulito (evita regex nella URL del nodo upload)
const item = $input.first().json;
const nome = (item.nome_cliente || 'unknown').replace(/[^a-zA-Z0-9]/g, '_');
const now = new Date();
const year = now.getFullYear();
const month = String(now.getMonth() + 1).padStart(2, '0');
const day = String(now.getDate()).padStart(2, '0');
const hours = String(now.getHours()).padStart(2, '0');
const mins = String(now.getMinutes()).padStart(2, '0');
const ts = year + month + day + '_' + hours + mins;
const pdf_filename = nome + '_' + ts + '.pdf';
return [{ json: { ...item, pdf_filename } }];

// Calcola l'header Authorization per PDFShift
const apiKey = 'sk_434182abf85c8ac8be982c4427d8c949bf41785c';
const encoded = Buffer.from('api:' + apiKey).toString('base64');
const item = $input.first();
return [{ json: { ...item.json, _pdfshift_auth: 'Basic ' + encoded } }];

// Prepara dati per Supabase
// Usa il filename pre-generato come fallback se l'upload non restituisce Key
const buildData = $('Build HTML').item.json;
const storageData = $input.first().json;
const genFilename = $('Genera Filename').item.json.pdf_filename || '';

// Supabase Storage returns { Key: 'consent-doc/filename.pdf' } on success
// Try both casing variants
const storageKey = storageData.Key || storageData.key || '';
const storagePath = storageKey.replace(/^consent-docs\//, '') || genFilename;

const email = buildData.email || '';
const codice_fiscale = buildData.codice_fiscale || '';
const indirizzo = buildData.residenza || '';
const today = new Date().toISOString().split('T')[0];

return [{ json: { email, codice_fiscale, indirizzo, storage_path: storagePath, session_date: today } }];
